"""
install_feedback.py
Run this ONCE from C:\portfolio-demo to install the feedback system.
python install_feedback.py
"""
import os

# --- src\models\recommendation.py ---
_b64_recommendation_py = ""

# --- src\db\recommendations_db.py ---
_b64_recommendations_db_py = ""

# --- src\price_updater.py ---
_b64_price_updater_py = ""

# --- approve.py ---
_b64_approve_py = ""

import base64, os

os.makedirs(os.path.dirname("src\models\recommendation.py") or ".", exist_ok=True)
open("src\models\recommendation.py", "w", encoding="utf-8").write(base64.b64decode(_b64_recommendation_py).decode("utf-8"))
print("  OK  src\models\recommendation.py")

os.makedirs(os.path.dirname("src\db\recommendations_db.py") or ".", exist_ok=True)
open("src\db\recommendations_db.py", "w", encoding="utf-8").write(base64.b64decode(_b64_recommendations_db_py).decode("utf-8"))
print("  OK  src\db\recommendations_db.py")

os.makedirs(os.path.dirname("src\price_updater.py") or ".", exist_ok=True)
open("src\price_updater.py", "w", encoding="utf-8").write(base64.b64decode(_b64_price_updater_py).decode("utf-8"))
print("  OK  src\price_updater.py")

os.makedirs(os.path.dirname("approve.py") or ".", exist_ok=True)
open("approve.py", "w", encoding="utf-8").write(base64.b64decode(_b64_approve_py).decode("utf-8"))
print("  OK  approve.py")

print()
print("All files installed. Run: python demo_run.py")